mapper.select:
select item_code, item_name, item_type_code, unit_code, spec, use_yn, created_at, created_by, updated_at, updated_by from mst_item where 1 = 1
and item_code ilike concat('%', #{itemCode}, '%')
and item_name ilike concat('%', #{itemName}, '%')
and item_type_code = #{itemTypeCode}
and use_yn = #{useYn}
order by item_code

select count(1)
from mst_item
where item_code = #{itemCode}
